# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import subprocess
import os
import tempfile
from google.cloud import storage


def image_converter(event, context):
    """Cloud Function triggered by Cloud Storage event to convert images using ImageMagick.
    
    Args:
        event (dict): The Cloud Storage event payload.
        context (google.cloud.functions.Context): The event context.
    """
    bucket_name = event['bucket']
    source_file = event['name']
    
    # Extract metadata and conversion options
    metadata = event.get('metadata', {})
    output_format = metadata.get('output_format', 'png')
    resize = metadata.get('resize', None)
    quality = metadata.get('quality', None)
    rotate = metadata.get('rotate', None)
    grayscale = metadata.get('grayscale', 'false')
    strip_metadata = metadata.get('strip_metadata', 'false')
    output_bucket = metadata.get('output_bucket', bucket_name)
    output_prefix = metadata.get('output_prefix', 'converted/')
    
    # Skip if file is already in the converted directory to avoid infinite loops
    if source_file.startswith(output_prefix):
        print(f"Skipping already converted file: {source_file}")
        return
    
    # Validate supported input formats
    supported_input_formats = ('.jpg', '.jpeg', '.png', '.gif', '.bmp', '.tiff', '.tif', '.webp', '.svg')
    file_extension = os.path.splitext(source_file)[1].lower()
    if file_extension not in supported_input_formats:
        print(f"Unsupported input format: {file_extension}. Skipping.")
        return
    
    # Initialize Cloud Storage client
    storage_client = storage.Client()
    source_bucket = storage_client.bucket(bucket_name)
    source_blob = source_bucket.blob(source_file)
    
    # Create temporary directory for processing
    with tempfile.TemporaryDirectory() as temp_dir:
        # Download the source file
        input_filename = os.path.basename(source_file)
        input_path = os.path.join(temp_dir, input_filename)
        
        print(f"Downloading gs://{bucket_name}/{source_file} to {input_path}")
        source_blob.download_to_filename(input_path)
        
        # Build output filename
        base_name = os.path.splitext(input_filename)[0]
        output_filename = f"{base_name}.{output_format}"
        output_path = os.path.join(temp_dir, output_filename)
        
        # Build ImageMagick convert command
        convert_cmd = ['convert', input_path]
        
        # Apply conversion options
        if resize:
            # e.g., "800x600", "50%", "800x600!"
            convert_cmd.extend(['-resize', resize])
        
        if quality:
            # Quality value 1-100
            convert_cmd.extend(['-quality', str(quality)])
        
        if rotate:
            # Rotation angle in degrees
            convert_cmd.extend(['-rotate', str(rotate)])
        
        if grayscale.lower() == 'true':
            convert_cmd.extend(['-colorspace', 'Gray'])
        
        if strip_metadata.lower() == 'true':
            convert_cmd.append('-strip')
        
        # Add output path
        convert_cmd.append(output_path)
        
        print(f"Running ImageMagick command: {' '.join(convert_cmd)}")
        
        # Execute the convert command
        return_code = subprocess.call(convert_cmd)
        
        if return_code != 0:
            error_msg = f"ImageMagick convert failed with return code {return_code} for file {source_file}"
            print(error_msg)
            raise RuntimeError(error_msg)
        
        # Verify output file was created
        if not os.path.exists(output_path):
            error_msg = f"Output file was not created: {output_path}"
            print(error_msg)
            raise RuntimeError(error_msg)
        
        output_file_size = os.path.getsize(output_path)
        print(f"Conversion successful. Output file size: {output_file_size} bytes")
        
        # Upload the converted file to the destination bucket
        dest_bucket = storage_client.bucket(output_bucket)
        dest_blob_name = f"{output_prefix}{output_filename}"
        dest_blob = dest_bucket.blob(dest_blob_name)
        
        # Set content type based on output format
        content_type_map = {
            'png': 'image/png',
            'jpg': 'image/jpeg',
            'jpeg': 'image/jpeg',
            'gif': 'image/gif',
            'bmp': 'image/bmp',
            'tiff': 'image/tiff',
            'tif': 'image/tiff',
            'webp': 'image/webp',
            'pdf': 'application/pdf',
            'svg': 'image/svg+xml',
        }
        content_type = content_type_map.get(output_format.lower(), 'application/octet-stream')
        
        # Add metadata to the converted file
        dest_blob.metadata = {
            'source_file': source_file,
            'source_bucket': bucket_name,
            'conversion_options': str({
                'output_format': output_format,
                'resize': resize,
                'quality': quality,
                'rotate': rotate,
                'grayscale': grayscale,
                'strip_metadata': strip_metadata,
            }),
        }
        
        print(f"Uploading converted file to gs://{output_bucket}/{dest_blob_name}")
        dest_blob.upload_from_filename(output_path, content_type=content_type)
        
        print(f"Successfully converted {source_file} to {dest_blob_name} "
              f"(format: {output_format}, size: {output_file_size} bytes)")
    
    return f"Converted {source_file} -> {dest_blob_name}"